import React, { useState, useEffect } from 'react';
import axios from 'axios';

axios.defaults.baseURL = '/api';

function App() {
  const [token, setToken] = useState(localStorage.getItem('token'));
  const [user, setUser] = useState(null);
  const [view, setView] = useState('dashboard');
  const [transactions, setTransactions] = useState([]);

  const headers = { Authorization: `Bearer ${token}` };

  const register = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/auth/register', { name: e.target.name.value, email: e.target.email.value, password: e.target.password.value });
      alert('Registered! Please login.');
    } catch (err) {
      alert(err.response.data.error);
    }
  };

  const login = async (e) => {
    e.preventDefault();
    try {
      const res = await axios.post('/auth/login', { email: e.target.email.value, password: e.target.password.value });
      setToken(res.data.token);
      localStorage.setItem('token', res.data.token);
      setUser(res.data.user);
      axios.defaults.headers.common.Authorization = `Bearer ${res.data.token}`;
    } catch (err) {
      alert(err.response.data.error);
    }
  };

  const logout = () => {
    setToken(null);
    localStorage.removeItem('token');
    delete axios.defaults.headers.common.Authorization;
  };

  const loadTransactions = async () => {
    try {
      const res = await axios.get('/transactions');
      setTransactions(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    if (token) {
      axios.defaults.headers.common.Authorization = `Bearer ${token}`;
      loadTransactions();
    }
  }, [token]);

  if (!token) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-blue-500 to-purple-600 flex items-center justify-center p-4">
        <div className="bg-white rounded-2xl shadow-2xl p-8 max-w-md w-full">
          <h1 className="text-3xl font-bold text-center text-gray-800 mb-8">FinTrack</h1>
          <form onSubmit={login} className="space-y-4">
            <input name="email" type="email" placeholder="Email" className="w-full p-3 border border-gray-300 rounded-lg" required />
            <input name="password" type="password" placeholder="Password" className="w-full p-3 border border-gray-300 rounded-lg" required />
            <button type="submit" className="w-full bg-blue-500 text-white p-3 rounded-lg font-semibold hover:bg-blue-600">Login</button>
          </form>
          <p className="text-center mt-4 text-sm text-gray-600">or</p>
          <form onSubmit={register} className="mt-4 space-y-4">
            <input name="name" type="text" placeholder="Full Name" className="w-full p-3 border border-gray-300 rounded-lg" required />
            <input name="email" type="email" placeholder="Email" className="w-full p-3 border border-gray-300 rounded-lg" required />
            <input name="password" type="password" placeholder="Password" className="w-full p-3 border border-gray-300 rounded-lg" required />
            <button type="submit" className="w-full bg-green-500 text-white p-3 rounded-lg font-semibold hover:bg-green-600">Register</button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100">
      <nav className="bg-white shadow-lg p-4">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <h1 className="text-2xl font-bold text-gray-800">FinTrack Dashboard</h1>
          <div className="flex space-x-4">
            <button onClick={() => setView('transactions')} className={`px-4 py-2 rounded-lg ${view === 'transactions' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}>Transactions</button>
            <button onClick={() => setView('budgets')} className={`px-4 py-2 rounded-lg ${view === 'budgets' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}>Budgets</button>
            <button onClick={() => setView('investments')} className={`px-4 py-2 rounded-lg ${view === 'investments' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}>Investments</button>
            <button onClick={() => setView('analytics')} className={`px-4 py-2 rounded-lg ${view === 'analytics' ? 'bg-blue-500 text-white' : 'bg-gray-200'}`}>Analytics</button>
            <button onClick={logout} className="bg-red-500 text-white px-4 py-2 rounded-lg font-semibold">Logout</button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto p-6">
        {view === 'dashboard' && (
          <div>
            <h2>Welcome, {user?.name}!</h2>
            <p>Recent Transactions: {transactions.slice(0, 5).map(t => `${t.type}: $${t.amount}`).join(', ') || 'None'}</p>
          </div>
        )}

        {view === 'transactions' && (
          <div>
            <h2 className="text-2xl font-bold mb-6">Transactions</h2>
            <form className="bg-white p-6 rounded-lg shadow mb-6" onSubmit={async (e) => {
              e.preventDefault();
              try {
                await axios.post('/transactions', {
                  amount: parseFloat(e.target.amount.value),
                  type: e.target.type.value,
                  category: e.target.category.value,
                  date: e.target.date.value
                });
                loadTransactions();
                e.target.reset();
              } catch (err) {
                alert(err.response.data.error);
              }
            }}>
              <div className="grid grid-cols-2 gap-4 mb-4">
                <input name="amount" type="number" step="0.01" placeholder="Amount" className="p-3 border rounded-lg" required />
                <input name="date" type="date" className="p-3 border rounded-lg" required />
              </div>
              <select name="type" className="p-3 border rounded-lg w-full mb-4" required>
                <option value="">Type</option>
                <option value="income">Income</option>
                <option value="expense">Expense</option>
              </select>
              <select name="category" className="p-3 border rounded-lg w-full mb-4" required>
                <option value="">Category</option>
                <option value="salary">Salary</option>
                <option value="food">Food</option>
                <option value="rent">Rent</option>
                <option value="other">Other</option>
              </select>
              <button type="submit" className="w-full bg-blue-500 text-white p-3 rounded-lg font-semibold">Add Transaction</button>
            </form>
            <div className="bg-white rounded-lg shadow overflow-hidden">
              <table className="w-full">
                <thead className="bg-gray-50">
                  <tr>
                    <th className="p-4 text-left">Date</th>
                    <th className="p-4 text-left">Type</th>
                    <th className="p-4 text-left">Category</th>
                    <th className="p-4 text-right">Amount</th>
                  </tr>
                </thead>
                <tbody>
                  {transactions.map(t => (
                    <tr key={t.id} className="border-t">
                      <td className="p-4">{t.date}</td>
                      <td className={`p-4 ${t.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                        {t.type.toUpperCase()}
                      </td>
                      <td className="p-4">{t.category}</td>
                      <td className={`p-4 font-semibold ${t.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                        ${t.amount}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {view === 'analytics' && (
          <div>
            <h2 className="text-2xl font-bold mb-6">Analytics (Jan 2024 example)</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="bg-white p-6 rounded-lg shadow text-center">
                <h3 className="text-lg font-semibold text-gray-700">Savings Rate</h3>
                <p className="text-3xl font-bold text-green-600">25%</p>
              </div>
              <div className="bg-white p-6 rounded-lg shadow text-center">
                <h3 className="text-lg font-semibold text-gray-700">Avg Expense Std Dev</h3>
                <p className="text-3xl font-bold text-blue-600">$150.50</p>
              </div>
              <div className="bg-white p-6 rounded-lg shadow text-center">
                <h3 className="text-lg font-semibold text-gray-700">Budget Usage</h3>
                <p className="text-3xl font-bold text-orange-600">75%</p>
              </div>
            </div>
          </div>
        )}

        {/* Similar placeholders for budgets, investments */}
      </main>
    </div>
  );
}

export default App;
